// --- 4. CALCOLO HASH TELEGRAM ---
const secretKey = CryptoJS.hmac("WebAppData", BOT_TOKEN);
const computedHashBytes = CryptoJS.hmac(secretKey, checkString);
const computedHash = computedHashBytes.map(b => b.toString(16).padStart(2, '0')).join('');

// --- 5. CONTROLLO SCADENZA (MAX 1 ORA) ---
const now = Math.floor(Date.now() / 1000);
const authDate = parseInt(data.auth_date);
const isExpired = (now - authDate) > 3600; // Scade dopo 3600 secondi (1 ora)

// --- 6. RISULTATO FINALE ---
const isHashValid = (computedHash === hashReceived);

return {
