// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Handover_Data
// DESC: Decripta destinatario e prepara le caption. 
//       Log per il Vault generato SOLO alla chiusura.
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;
const body = item.body || {};
const owner = item.owner_data || {};
const ash = body.ash;
const SECRET_KEY = 'TrinAI-Autorize-Transaction-2=2&';

// --- 1. DECRIPTAZIONE ASH ---
if (!ash || !ash.includes('.')) {
    throw new Error("Ash di destinazione non valido.");
}

const [encodedPayload, sigReceived] = ash.split('.');
const decodedPayload = Buffer.from(encodedPayload, 'base64').toString('utf-8');

function generateSignature(str, key) {
    let hash = 0;
    const combined = str + key;
    for (let i = 0; i < combined.length; i++) {
        const char = combined.charCodeAt(i);
        hash = ((hash << 5) - hash) + char;
        hash = hash & hash; 
    }
    return Math.abs(hash).toString(16);
}

if (sigReceived !== generateSignature(decodedPayload, SECRET_KEY)) {
    throw new Error("Firma Ash non valida. Accesso negato.");
}

const [targetChatId, timestamp, webhookId] = decodedPayload.split('|');

// --- 2. PULIZIA TESTO ---
function cleanHTML(t) {
    return t ? String(t).replace(/<(?!b|i|u|code|a|pre|\/b|\/i|\/u|\/code|\/a|\/pre)[^>]+>/gi, '') : '';
}
const cleanText = cleanHTML(body.message_text);

// --- 3. PAYLOAD PER IL CLIENTE (Sempre generato) ---
const customerMsg = `
🎧 <b>AGGIORNAMENTO ASSISTENZA</b>
━━━━━━━━━━━━━━━━━━━━
Ciao, il team di <b>${owner.ragione_sociale}</b> ha risposto alla tua richiesta:

"${cleanText}"

${body.close_ticket ? '\n📍 <i>La sessione di assistenza è stata chiusa.</i>' : ''}
━━━━━━━━━━━━━━━━━━━━`;

const payload_customer = {
    chat_id: targetChatId,
    caption: customerMsg,
    parse_mode: "HTML"
};

// --- 4. LOG PER IL VAULT (Solo se close_ticket è true) ---
let payload_vault = null;
if (body.close_ticket === true) {
    const vaultMsg = `
🗄️ <b>HANDOVER CHIUSO: LOG ARCHIVIO</b>
━━━━━━━━━━━━━━━━━━━━
👤 <b>OPERATORE:</b> <b>${item.user?.first_name || 'Owner'}</b>
🎯 <b>CLIENTE ID:</b> <code>${targetChatId}</code>

💬 <b>ULTIMO MESSAGGIO:</b>
<i>"${cleanText}"</i>

📎 <b>ALLEGATO INVIATO:</b> <code>${body.file_data?.file_name || 'Nessuno'}</code>
✅ <b>STATUS:</b> CERTIFICATO E CHIUSO
━━━━━━━━━━━━━━━━━━━━`;

    payload_vault = {
        method: "sendMessage", // Messaggio testuale, non mandiamo il file al manager
        chat_id: owner.chat_id,
        text: vaultMsg,
        parse_mode: "HTML"
    };
}

// --- 5. RITORNO DATI ---
return [{
    json: {
        ...item,
        auth_result: {
            isValid: true,
            chatId: targetChatId
        },
        payload_customer: payload_customer,
        payload_owner: payload_vault,
        send_to_owner: (payload_vault !== null) // Flag utile per uno Switch in n8n
    }
}];

const item = $input.first().json;
const { ids, owner_data: owner, body, user, stakeholder } = item;

// 1. PULIZIA TESTO (Rimuoviamo tag HTML non supportati da Telegram)
function cleanHTML(t) {
    return t ? String(t).replace(/<(?!b|i|u|code|a|pre|\/b|\/i|\/u|\/code|\/a|\/pre)[^>]+>/gi, '') : '';
}
const cleanText = cleanHTML(body.message_text);

// 2. RECUPERO NOME OPERATORE (Chi sta scrivendo ora)
const operatore = user?.first_name || "Owner";

// 3. PAYLOAD PER IL CLIENTE (Destinatario finale)
// Usiamo ids.customer_id estratto dal Decoder
item.payload_customer = {
    method: "sendMessage",
    chat_id: ids.customer_id,
    text: `🎧 <b>RISPOSTA DA ${owner.ragione_sociale.toUpperCase()}</b>\n━━━━━━━━━━━━━━━━━━━━\n"<i>${cleanText}</i>"\n\n${body.close_ticket ? '📍 <b>Nota:</b> <i>Il ticket è stato risolto e la sessione chiusa.</i>' : '💬 <i>Puoi rispondere a questo messaggio se hai bisogno di altro.</i>'}`,
    parse_mode: "HTML"
};

// 4. LOG PER IL VAULT DELL'OWNER (Solo alla chiusura)
if (body.close_ticket === true) {
    const nomeCliente = stakeholder.user_ref?.nome || "Utente";

    item.payload_owner = {
        method: "sendMessage",
        chat_id: ids.owner_id,
        text: `🗄️ <b>HANDOVER CHIUSO E ARCHIVIATO</b>\n━━━━━━━━━━━━━━━━━━━━\n👤 <b>Operatore:</b> ${operatore}\n🎯 <b>Cliente:</b> ${nomeCliente}\n🆔 <b>User ID:</b> <code>${ids.customer_id}</code>\n\n💬 <b>Ultima risposta:</b>\n"<i>${cleanText}</i>"\n\n✅ <b>STATUS:</b> RISOLTO`,
        parse_mode: "HTML"
    };
